import { Activity, Day, Trip } from '../models/index.js';
import { ApiError } from '../utils/apiError.js';
import { ApiResponse } from '../utils/apiResponse.js';
import { asyncHandler } from '../utils/asyncHandler.js';

export const createActivity = asyncHandler(async (req, res) => {
  const { tripId } = req.params;
  const { dayId, title, description, start_time, end_time, type } = req.body;

  if (!dayId || !title) {
    throw new ApiError(400, 'dayId and title are required');
  }
  // Verify day belongs to trip
  const day = await Day.findOne({ where: { id: dayId, TripId: tripId } });
  if (!day) {
    throw new ApiError(404, 'Day not found in this trip');
  }
  // Get max order_index for the day
  const maxOrder = await Activity.max('order_index', {
    where: { DayId: dayId }
  });
  const orderIndex = maxOrder ? maxOrder + 1 : 0;
  const activity = await Activity.create({
    title,
    description,
    start_time,
    end_time,
    type,
    order_index: orderIndex,
    DayId: dayId
  });
  return res
    .status(201)
    .json(new ApiResponse(201, activity, 'Activity created successfully'));
});

export const updateActivity = asyncHandler(async (req, res) => {
  const { activityId } = req.params;
  const updates = req.body;

  const activity = await Activity.findByPk(activityId);
  if (!activity) {
    throw new ApiError(404, 'Activity not found');
  }
  const updatedActivity = await activity.update(updates);
  return res
    .status(200)
    .json(
      new ApiResponse(200, updatedActivity, 'Activity updated successfully')
    );
});

export const deleteActivity = asyncHandler(async (req, res) => {
  const { activityId } = req.params;

  const activity = await Activity.findByPk(activityId);
  if (!activity) {
    throw new ApiError(404, 'Activity not found');
  }
  await activity.destroy();
  return res
    .status(200)
    .json(new ApiResponse(200, null, 'Activity deleted successfully'));
});

export const reorderActivities = asyncHandler(async (req, res) => {
  // Expected payload: [{ id: "uuid", order_index: 0 }, { id: "uuid-2", order_index: 1 }]
  const { tripId } = req.params;
  const { activities } = req.body;

  if (!Array.isArray(activities)) {
    throw new ApiError(400, 'Activities array is required');
  }
  for (const item of activities) {
    if (item.id && item.order_index !== undefined) {
      await Activity.update(
        { order_index: item.order_index },
        { where: { id: item.id } }
      );
    }
  }
  return res
    .status(200)
    .json(new ApiResponse(200, null, 'Activities reordered successfully'));
});

import { User } from '../models/index.js';
import { ApiError } from '../utils/apiError.js';
import { ApiResponse } from '../utils/apiResponse.js';
import { asyncHandler } from '../utils/asyncHandler.js';

const generateAccessTokens = async (userId) => {
  try {
    const user = await User.findByPk(userId);
    const accessToken = user.generateAccessToken();
    return accessToken;
  } catch {
    throw new ApiError(
      500,
      'Something went wrong while generating access token'
    );
  }
};

export const handleOAuthLogin = asyncHandler(async (req, res) => {
  if (!req.user) {
    return res.redirect(`${process.env.CORS_ORIGIN}/login?error=OAuthFailed`);
  }
  const accessToken = await generateAccessTokens(req.user.id);
  const options = {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production'
  };
  res.cookie('accessToken', accessToken, options);
  res.redirect(`${process.env.CORS_ORIGIN}/`);
});

export const registerUser = asyncHandler(async (req, res) => {
  const { name, email, password } = req.body;

  if (!name || !email || !password) {
    throw new ApiError(400, 'All fields are required');
  }
  const existedUser = await User.findOne({ where: { email } });
  if (existedUser) {
    throw new ApiError(409, 'User with email already exists');
  }
  const user = await User.create({
    name,
    email,
    password
  });

  const createdUser = await User.findByPk(user.id, {
    attributes: { exclude: ['password'] }
  });

  if (!createdUser) {
    throw new ApiError(500, 'Something went wrong while registering the user');
  }
  return res
    .status(201)
    .json(new ApiResponse(201, createdUser, 'User registered successfully'));
});

export const loginUser = asyncHandler(async (req, res) => {
  const { email, password } = req.body;

  if (!email || !password) {
    throw new ApiError(400, 'Email and password are required');
  }
  const user = await User.findOne({ where: { email } });
  if (!user) {
    throw new ApiError(404, 'User does not exist');
  }
  const isPasswordValid = await user.isPasswordCorrect(password);
  if (!isPasswordValid) {
    throw new ApiError(401, 'Invalid user credentials');
  }
  const accessToken = await generateAccessTokens(user.id);
  const loggedInUser = await User.findByPk(user.id, {
    attributes: { exclude: ['password'] }
  });
  const options = {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production'
  };
  return res
    .status(200)
    .cookie('accessToken', accessToken, options)
    .json(
      new ApiResponse(
        200,
        {
          user: loggedInUser,
          accessToken
        },
        'User logged in successfully'
      )
    );
});

export const logoutUser = asyncHandler(async (req, res) => {
  const options = {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production'
  };
  return res
    .status(200)
    .clearCookie('accessToken', options)
    .json(new ApiResponse(200, {}, 'User logged out successfully'));
});

export const getMe = asyncHandler(async (req, res) => {
  return res
    .status(200)
    .json(new ApiResponse(200, req.user, 'User details fetched successfully'));
});

import { DataTypes } from 'sequelize';
import { sequelize } from '../config/db.js';
import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';

const User = sequelize.define(
  'User',
  {
    id: {
      type: DataTypes.UUID,
      defaultValue: DataTypes.UUIDV4,
      primaryKey: true
    },
    name: {
      type: DataTypes.STRING,
      allowNull: false
    },
    email: {
      type: DataTypes.STRING,
      allowNull: false,
      unique: true,
      validate: { isEmail: true }
    },
    password: {
      type: DataTypes.STRING,
      allowNull: true
    },
    auth_provider: {
      type: DataTypes.ENUM('LOCAL', 'GOOGLE', 'GITHUB'),
      defaultValue: 'LOCAL'
    },
    google_id: {
      type: DataTypes.STRING,
      allowNull: true
    },
    github_id: {
      type: DataTypes.STRING,
      allowNull: true
    }
  },
  {
    timestamps: true,
    hooks: {
      beforeSave: async (user) => {
        if (user.changed('password') && user.password) {
          user.password = await bcrypt.hash(user.password, 10);
        }
      }
    },
    indexes: [{ fields: ['google_id'] }, { fields: ['github_id'] }]
  }
);

// Instance methods
User.prototype.isPasswordCorrect = async function (password) {
  if (!this.password) {
    return false;
  }
  return await bcrypt.compare(password, this.password);
};

User.prototype.generateAccessToken = function () {
  return jwt.sign(
    { id: this.id, email: this.email, name: this.name },
    process.env.JWT_SECRET,
    { expiresIn: process.env.JWT_EXPIRES_IN }
  );
};

export { User };

import { connectDB, sequelize } from './src/config/db.js';
import { User, Trip } from './src/models/index.js';

async function testApi() {
  try {
    await connectDB();
    let user = await User.findOne();
    if (!user) {
      user = await User.create({
        name: 'Test',
        email: 'test@test.com',
        password: 'password'
      });
    }

    // Generate a token
    const token = user.generateAccessToken();
    // TODO: don't use direct url use variables using env
    const res = await fetch('http://localhost:8000/api/v1/trips', {
      headers: {
        Authorization: `Bearer ${token}`
      }
    });
    const data = await res.json();
    console.log('Success! Status:', res.status, 'Data:', data);
  } catch (error) {
    console.error('API Error occurred:', error.message);
  } finally {
    await sequelize.close();
  }
}

testApi();
